using System;
using Foundation;
using AppKit;
using AnalysisITC.GUI.MacOS.CustomViews;
using System.Collections.Generic;
using System.Linq;
using AnalysisITC.AppClasses.AnalysisClasses;

namespace AnalysisITC
{
    public partial class FittingOptionsPopoverViewController : NSViewController
    {
        // Set by the presenting view controller before the popover appears.
        // The popover never owns or mutates the workspace — it only reads context
        // for display and calls workspace methods for user-driven changes.
        public AnalysisWorkspace Workspace { get; set; }

        Dictionary<AttributeKey, ExperimentAttribute> draftOptions;

        List<ParameterValueAdjustmentView> ParameterControls = new();
        List<OptionAdjustmentView> OptionControls = new();

        bool _shouldRevertChanges = true;

        // ── Constructor ────────────────────────────────────────────────────

        public FittingOptionsPopoverViewController(IntPtr handle) : base(handle)
        {
            OptionAdjustmentView.RefreshLists += OnRefreshLists;
        }

        // ── Helpers ────────────────────────────────────────────────────────

        // Null-safe accessors so every call site doesn't need a guard.
        bool HasContext => Workspace?.IsReady == true;

        IEnumerable<Parameter> ExposedParameters =>
            HasContext ? Workspace.Context.ExposedParameters : Enumerable.Empty<Parameter>();

        IDictionary<AttributeKey, ExperimentAttribute> ExposedOptions =>
            HasContext ? Workspace.Context.ExposedModelOptions : new Dictionary<AttributeKey, ExperimentAttribute>();

        // ── OptionAdjustmentView callback ──────────────────────────────────

        // OptionAdjustmentView fires this when one option changes state that
        // may affect the display of other options or parameters (e.g. toggling
        // a binding mode that changes which parameters are visible).
        // We sync the mutated live dict back to session state immediately so
        // the workspace knows about the change, then refresh all control states.
        private void OnRefreshLists(object sender, EventArgs e)
        {
            // OptionAdjustmentView may have mutated ExposedModelOptions directly.
            // Persist that into session state without triggering a full rebuild yet —
            // the user hasn't pressed Apply, so we only want a visual refresh.
            Workspace?.SyncModelOptionsToSession();

            foreach (var sv in OptionStackView.Views.OfType<OptionAdjustmentView>())
                sv.UpdateState(draftOptions);

            foreach (var sv in ParameterStackView.Views.OfType<ParameterValueAdjustmentView>())
                sv.UpdateState(draftOptions);
        }

        // ── Lifecycle ──────────────────────────────────────────────────────

        public override void ViewWillAppear()
        {
            base.ViewWillAppear();

            // Resolve workspace from the presenting VC rather than requiring injection via PrepareForSegue.
            if (PresentingViewController is DataAnalysisViewController davc)
                Workspace = davc.Workspace;

            _shouldRevertChanges = true;

            // ── Solver option controls ────────────────────────────────────
            SolverAlgorithmControl.SelectSegment((int)FittingOptionsController.Algorithm);
            UseWeightedControl.State = FittingOptionsController.UseErrorWeightedFitting ? NSCellStateValue.On : NSCellStateValue.Off;

            ErrorIterationsControl.DoubleValue = Math.Log10(FittingOptionsController.BootstrapIterations);
            ErrorIterationLabel.IntValue = (int)Math.Pow(10, ErrorIterationsControl.DoubleValue);

            if (!FittingOptionsController.IncludeConcentrationVariance)
                IncludeConcErrorControl.SelectedSegment = 0;
            else
                IncludeConcErrorControl.SelectedSegment = FittingOptionsController.EnableAutoConcentrationVariance ? 2 : 1;

            ErrorMethodControl.SelectedSegment = (int)FittingOptionsController.ErrorEstimationMethod;

            UnlockParametersForErrorEstimationControl.State = FittingOptionsController.UnlockBootstrapParameters ? NSCellStateValue.On : NSCellStateValue.Off;

            // ── Model options views ───────────────────────────────────────
            if (!HasContext) return;

            draftOptions = Workspace.Context.ExposedModelOptions.ToDictionary(kvp => kvp.Key, kvp => kvp.Value.Copy());

            foreach (var opt in draftOptions.Reverse())
            {
                var sv = new OptionAdjustmentView(new CoreGraphics.CGRect(0, 0, OptionStackView.Frame.Width, 16), opt.Value);
                sv.UpdateState(draftOptions);
                OptionControls.Add(sv);
                OptionStackView.InsertArrangedSubview(sv, 0);
            }

            // ── Parameter views ───────────────────────────────────────────
            foreach (var par in ExposedParameters.Reverse())
            {
                var sv = new ParameterValueAdjustmentView(new CoreGraphics.CGRect(0, 0, ParameterStackView.Frame.Width, 16), par);
                sv.UpdateState(draftOptions);
                ParameterControls.Add(sv);
                ParameterStackView.InsertArrangedSubview(sv, 0);
            }

            // ── Hide empty sections ───────────────────────────────────────
            bool hasParams = ExposedParameters.Any();
            InitialValuesHeader.Hidden = !hasParams;
            InitialValuesLine.Hidden = !hasParams;
            ParameterStackView.Hidden = !hasParams;

            bool hasOptions = draftOptions.Any();
            ModelOptionsHeader.Hidden = !hasOptions;
            ModelOptionsLine.Hidden = !hasOptions;
            OptionStackView.Hidden = !hasOptions;
        }

        public override void ViewDidDisappear()
        {
            foreach (var sv in ParameterControls) sv.Dispose();
            base.ViewDidDisappear();
        }

        public override void ViewWillDisappear()
        {
            base.ViewWillDisappear();

            OptionAdjustmentView.RefreshLists -= OnRefreshLists;

            // Some options affect other UI elements and are applied immediately.
            // If the user dismissed without pressing Apply, revert them.
            if (_shouldRevertChanges)
            {
                foreach (var sv in OptionControls) sv.Revert();

                // Sync the reverted state back into session state so session
                // and context are consistent again after the revert.
                Workspace?.SyncModelOptionsToSession();
            }
        }

        // ── Actions ────────────────────────────────────────────────────────

        partial void ErrorIterationSliderChanged(NSSlider sender)
        {
            ErrorIterationLabel.IntValue = (int)Math.Pow(10, ErrorIterationsControl.DoubleValue);
        }

        partial void ApplyOptions(NSObject sender)
        {
            _shouldRevertChanges = false;

            try
            {
                // ── Solver options ────────────────────────────────────────
                FittingOptionsController.ErrorEstimationMethod = (ErrorEstimationMethod)(int)ErrorMethodControl.SelectedSegment;
                FittingOptionsController.BootstrapIterations = (int)Math.Pow(10, ErrorIterationsControl.DoubleValue);
                FittingOptionsController.IncludeConcentrationVariance = IncludeConcErrorControl.SelectedSegment > 0;
                FittingOptionsController.EnableAutoConcentrationVariance = IncludeConcErrorControl.SelectedSegment == 2;
                FittingOptionsController.Algorithm = (SolverAlgorithm)(int)SolverAlgorithmControl.SelectedSegment;
                FittingOptionsController.UseErrorWeightedFitting = UseWeightedControl.State == NSCellStateValue.On;
                FittingOptionsController.UnlockBootstrapParameters = UnlockParametersForErrorEstimationControl.State == NSCellStateValue.On;

                // ── Parameter overrides ───────────────────────────────────
                foreach (var sv in ParameterControls)
                {
                    if (sv.ShouldResetParameter)
                    {
                        // Remove the stored override; the next rebuild restores the data default.
                        Workspace?.ResetParameterOverride(sv.Parameter.Key);
                    }
                    else if (sv.HasBeenAffectedFlag)
                    {
                        Workspace?.SetParameterOverride(sv.Key, sv.Value, sv.Locked);
                    }
                }

                // ── Model options ─────────────────────────────────────────
                foreach (var sv in OptionControls)
                    sv.ApplyOptions();

                //Workspace?.SyncModelOptionsToSession();
                Workspace?.ReplaceModelOptions(draftOptions, rebuild: false);
                Workspace?.TryRebuild();

                DismissViewController(this);
            }
            catch (Exception ex)
            {
                AppEventHandler.DisplayHandledException(ex);
            }
        }
    }
}



